@app.get("/v1/models")
def list_models(request: Request, tenant_id: Optional[str] = None):
    tid = _get_tenant_id(request, tenant_id)
    out = []
    with _store_lock:
        for k, v in _models.items():
            if v.get("tenant_id") == tid:
                out.append(
                    {
                        "model_id": v.get("model_id"),
                        "filename": v.get("filename"),
                        "content_type": v.get("content_type"),
                        "sha256": v.get("sha256"),
                        "bytes": v.get("bytes"),
                        "created_at": v.get("created_at"),
                        "last_access": v.get("last_access"),
                    }
                )
    return {"tenant_id": tid, "models": sorted(out, key=lambda x: (x["model_id"] or ""))}

